-- ==============================================================
-- Objective : Find users who have never posted, liked, or commented.
-- Example GenAI Prompt :
--   "Find users who have never posted, liked, or commented."
-- --------------------------------------------------------------
-- Your Code ...

SELECT
    u.user_id,
    u.username
FROM users u
LEFT JOIN posts p
    ON u.user_id = p.user_id
LEFT JOIN likes l
    ON u.user_id = l.user_id
LEFT JOIN comments c
    ON u.user_id = c.user_id
WHERE p.post_id IS NULL
  AND l.like_id IS NULL
  AND c.comment_id IS NULL;


-- Solution Summary -- 
/*Approach (Schema-Based)
Use the users table as the base set of all users.
Check for the absence of records related to each user in:
posts (no content created)
likes (no likes given)
comments (no comments made)
Filter users who have no matches in all three interaction tables.
Return user identifiers (and optionally usernames).
Key Definition
Never interacted user = a user with:
zero posts
zero likes
zero comments
Outcome
The result highlights completely inactive users—those who are registered on the platform
 but have never engaged with content in any measurable way.
*/


-- ==============================================================
-- Q10. Top Countries with Most Influencers
-- ==============================================================
-- Objective : Identify countries with the highest number of influencers.
-- Example GenAI Prompt :
--   "Generate SQL to find countries that have the most followed users."
-- --------------------------------------------------------------
-- Your Code ...
SELECT
    country,
    total_followers
FROM (
    SELECT
        u.country,
        COUNT(f.follower_user_id) AS total_followers
    FROM users u
    JOIN followers f
        ON u.user_id = f.user_id
    GROUP BY u.country
) t
WHERE total_followers = (
    SELECT MAX(total_followers)
    FROM (
        SELECT COUNT(follower_user_id) AS total_followers
        FROM followers f
        JOIN users u
            ON f.user_id = u.user_id
        GROUP BY u.country
    ) x
);

-- Solution Summary -- 
/*Approach (Schema-Based)
Use the followers table to count how many followers each user has.
user_id represents the user being followed.
Join the users table to map each followed user to their country.
Aggregate follower counts at the country level by summing followers of users from the same country.
Compare totals to identify countries with the highest overall follower presence.
Key Metric
Total Followers per Country
= sum of all follower relationships for users belonging to that country.
Outcome
The result highlights countries that host highly followed (influential) users, not just many users overall.
*/


-- ==============================================================
-- BONUS CHALLENGES
-- ==============================================================
-- 1. Engagement rate = (likes + comments) / posts
-- 2. Mutual followers
-- 3. Most used hashtags by top 5 influencers
-- 4. Country-wise engagement leaderboard
-- --------------------------------------------------------------
# 1
SELECT
    u.user_id,
    u.username,
    (COUNT(DISTINCT l.like_id) + COUNT(DISTINCT c.comment_id)) * 1.0
    / NULLIF(COUNT(DISTINCT p.post_id), 0) AS engagement_rate
FROM users u
LEFT JOIN posts p
    ON u.user_id = p.user_id
LEFT JOIN likes l
    ON p.post_id = l.post_id
LEFT JOIN comments c
    ON p.post_id = c.post_id
GROUP BY u.user_id, u.username;

# 2
SELECT
    f1.user_id AS user_1,
    f1.follower_user_id AS user_2
FROM followers f1
JOIN followers f2
    ON f1.user_id = f2.follower_user_id
   AND f1.follower_user_id = f2.user_id
WHERE f1.user_id < f1.follower_user_id;

# 3
WITH top_influencers AS (
    SELECT
        u.user_id
    FROM users u
    JOIN followers f
        ON u.user_id = f.user_id
    GROUP BY u.user_id
    ORDER BY COUNT(f.follower_user_id) DESC
    LIMIT 5
)
SELECT
    h.hashtag_id,
    h.tag_name,
    COUNT(ph.post_id) AS usage_count
FROM top_influencers ti
JOIN posts p
    ON ti.user_id = p.user_id
JOIN post_hashtags ph
    ON p.post_id = ph.post_id
JOIN hashtags h
    ON ph.hashtag_id = h.hashtag_id
GROUP BY h.hashtag_id, h.tag_name
ORDER BY usage_count DESC;

# 4
SELECT
    u.country,
    COUNT(DISTINCT l.like_id) + COUNT(DISTINCT c.comment_id) AS total_engagement
FROM users u
JOIN posts p
    ON u.user_id = p.user_id
LEFT JOIN likes l
    ON p.post_id = l.post_id
LEFT JOIN comments c
    ON p.post_id = c.post_id
GROUP BY u.country
ORDER BY total_engagement DESC;

